      try {
        val s = scala.io.Source.fromFile(confPath)
        try {
          (Right(
            s.mkString
          ))
        } catch {
          case e: Exception => Left("ERROR")
        } finally {
          s.close
        }
      } catch {
        case e: Exception => Left("ERROR")
      }
    } else {
      Left("Dosen't configure Logback")
    }
  }
}

class Logs () {
